import { ArrayList } from '../utils/array-utils';
import { pushToLayers, createDuplicateLayerNode } from './append-nodes';
import { createSeries, pushToSeries } from './series';
import { getLayersCount, getPanesCount, getPanes } from './nodelist-helpers';

export function Layer() {
    this.count = 0;
    this.domain = new ArrayList();
    this.splitClusters = new ArrayList();
    this.groups = new Array(0);
    this.panes = {};
}

Layer.prototype = {
    constructor: Layer,
    pushToLayers: pushToLayers,
    createSeries: createSeries,
    pushToSeries: pushToSeries,
    getLayersCount: getLayersCount,
    getPanesCount: getPanesCount,
    getPanes: getPanes,
    createDuplicateLayerNode: createDuplicateLayerNode
};
